import { TabId } from '../common/TabTypes';
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct HomePage {
  goToTab: (tab: TabId) => void = () => {};
  onCheckIn: () => void = () => {};

  @State recommendation: string = '番茄鸡蛋打卤面';
  @State fridgeItems: string[] = ['番茄', '鸡蛋', '面条', '青菜', '牛肉'];
  @State recentCheckins: { id: string; dish: string; date: string; mood: string }[] = [
    { id: '1', dish: '番茄鸡蛋打卤面', date: '今天 12:30', mood: '满足' },
    { id: '2', dish: '清炒西兰花', date: '昨天 18:45', mood: '健康' },
    { id: '3', dish: '红烧牛肉饭', date: '6月16日', mood: '治愈' },
  ];

  build() {
    Scroll() {
      Column() {
        this.TodayRecommendationCard()
        this.QuickGrid()
        this.FridgeSummary()
        this.RecentCheckins()
      }
      .width('100%')
      .padding(Theme.pageHorizontalPadding)
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .scrollBar(BarState.Off)
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  TodayRecommendationCard() {
    Row() {
      Column() {
        Text('今日推荐')
          .fontSize(11)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.tomato)
          .padding({ left: 10, right: 10, top: 4, bottom: 4 })
          .backgroundColor('rgba(232,93,78,0.10)')
          .borderRadius(12)
          .margin({ bottom: 10 })

        Text(this.recommendation)
          .fontSize(22)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.brown)
          .lineHeight(28)
          .margin({ bottom: 6 })

        Text('酸甜开胃，15 分钟上桌')
          .fontSize(13)
          .fontColor(Theme.brownMid)
          .margin({ bottom: 14 })

        Row() {
          Text('快手').QuickTag();
          Text('暖胃').QuickTag();
          Text('家常').QuickTag();
        }
        .margin({ bottom: 16 })

        Button() {
          Row() {
            SvgIcon({ variant: 'jumpWheel', iconSize: 16, color: '#FFFFFF' })
            Text('再转一次')
              .fontSize(14)
              .fontWeight(FontWeight.Bold)
              .fontColor('#FFFFFF')
              .margin({ left: 6 })
          }
        }
        .id('home-spin-wheel-button')
        .type(ButtonType.Normal)
        .borderRadius(Theme.radiusButton)
        .backgroundColor(Theme.tomato)
        .linearGradient(BrandGradient.primary)
        .padding({ left: 20, right: 20, top: 10, bottom: 10 })
        .shadow(Theme.shadowFloat())
        .onClick(() => this.goToTab('tab-wheel'))
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)

      Column() {
        SvgIcon({ variant: 'chefHat', iconSize: 56, color: Theme.tomato })
      }
      .width(96)
      .height(96)
      .borderRadius(48)
      .backgroundColor('#FFFFFF')
      .justifyContent(FlexAlign.Center)
      .shadow({ radius: 18, color: 'rgba(62,39,35,0.10)', offsetX: 0, offsetY: 6 })
    }
    .id('home-today-recommendation-card')
    .width('100%')
    .padding(22)
    .borderRadius(Theme.radiusHero)
    .linearGradient(BrandGradient.heroCard)
    .shadow(Theme.shadowCard())
    .margin({ top: 12 })
    .justifyContent(FlexAlign.SpaceBetween)
  }

  @Builder
  QuickGrid() {
    Text('快捷入口')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 24, bottom: 12 })

    Grid() {
      GridItem() {
        this.QuickItem('转盘', 'wheelIcon', '#FFF0ED', Theme.tomato, 'home-spin-wheel-button', () => this.goToTab('tab-wheel'))
      }
      GridItem() {
        this.QuickItem('冰箱', 'fridge', '#EEF7EA', Theme.avocado, 'home-ingredients-button', () => this.goToTab('tab-ingredients'))
      }
      GridItem() {
        this.QuickItem('发现', 'discoverIcon', '#FFF8E1', Theme.egg, 'home-discover-button', () => this.goToTab('tab-discover'))
      }
      GridItem() {
        this.QuickItem('记录', 'recordsIcon', '#EDEAF9', Theme.blueberry, 'home-records-button', () => this.goToTab('tab-records'))
      }
    }
    .columnsTemplate('1fr 1fr 1fr 1fr')
    .columnsGap(12)
    .width('100%')
  }

  @Builder
  QuickItem(label: string, icon: string, bg: string, color: string, id: string, onClick: () => void) {
    Column() {
      Column() {
        SvgIcon({ variant: icon, iconSize: 24, color: color })
      }
      .width(44)
      .height(44)
      .borderRadius(22)
      .backgroundColor(bg)
      .justifyContent(FlexAlign.Center)
      .margin({ bottom: 8 })

      Text(label)
        .fontSize(12)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.brown)
    }
    .id(id)
    .width('100%')
    .padding({ top: 14, bottom: 14 })
    .backgroundColor(Theme.cardBg)
    .borderRadius(Theme.radiusCard)
    .shadow(Theme.shadowCard())
    .onClick(onClick)
  }

  @Builder
  FridgeSummary() {
    Text('我的冰箱')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 24, bottom: 12 })

    Column() {
      Row() {
        Text('现有食材')
          .fontSize(16)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.brown)
        Text(`${this.fridgeItems.length} 种`)
          .fontSize(12)
          .fontColor(Theme.brownMid)
      }
      .width('100%')
      .justifyContent(FlexAlign.SpaceBetween)
      .margin({ bottom: 12 })

      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(this.fridgeItems, (item: string) => {
          Text(item)
            .fontSize(12)
            .fontColor(Theme.brownMid)
            .padding({ left: 12, right: 12, top: 6, bottom: 6 })
            .backgroundColor(Theme.cardMutedBg)
            .borderRadius(14)
            .margin({ right: 8, bottom: 8 })
        }, (item: string) => item)
      }
      .width('100%')
    }
    .id('home-my-fridge-summary')
    .width('100%')
    .padding(18)
    .backgroundColor(Theme.cardBg)
    .borderRadius(Theme.radiusCard)
    .shadow(Theme.shadowCard())
  }

  @Builder
  RecentCheckins() {
    Text('最近打卡')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 24, bottom: 12 })

    List({ space: 12 }) {
      ForEach(this.recentCheckins, (checkin: { id: string; dish: string; date: string; mood: string }) => {
        ListItem() {
          Column() {
            Text(checkin.date)
              .fontSize(11)
              .fontColor(Theme.brownLight)
              .margin({ bottom: 6 })
            Text(checkin.dish)
              .fontSize(15)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brown)
              .margin({ bottom: 4 })
            Text(`心情：${checkin.mood}`)
              .fontSize(11)
              .fontColor(Theme.brownMid)
          }
          .width(140)
          .padding(14)
          .backgroundColor(Theme.cardBg)
          .borderRadius(Theme.radiusCard)
          .shadow(Theme.shadowCard())
          .alignItems(HorizontalAlign.Start)
        }
        .id(`home-checkin-${checkin.id}`)
      }, (checkin: { id: string }) => checkin.id)
    }
    .id('home-recent-checkins-list')
    .listDirection(Axis.Horizontal)
    .scrollBar(BarState.Off)
    .width('100%')
    .height(120)
  }
}

@Extend(Text)
function QuickTag() {
  .fontSize(11)
  .fontColor(Theme.brownMid)
  .padding({ left: 10, right: 10, top: 4, bottom: 4 })
  .backgroundColor(Theme.cardBg)
  .borderRadius(12)
  .margin({ right: 6 })
}

