import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

interface WheelItem {
  id: string;
  name: string;
}

@Component
export struct WheelPage {
  onBack: () => void = () => {};
  onShareCard: () => void = () => {};
  onAddCheckin: (dish: string) => void = () => {};

  @State wheelItems: WheelItem[] = [
    { id: '1', name: '牛肉面' },
    { id: '2', name: '番茄炒蛋' },
    { id: '3', name: '沙拉' },
    { id: '4', name: '炒饭' },
    { id: '5', name: '煎饼果子' },
    { id: '6', name: '麻辣烫' },
  ];
  @State customItems: WheelItem[] = [
    { id: 'c1', name: '火锅' },
    { id: 'c2', name: '日料' },
    { id: 'c3', name: '披萨' },
  ];
  @State newItemName: string = '';
  @State resultName: string = '番茄鸡蛋打卤面';
  @State showResult: boolean = true;
  @State rotation: number = 0;
  @State isSpinning: boolean = false;

  private allItems(): WheelItem[] {
    return [...this.wheelItems, ...this.customItems];
  }

  build() {
    Stack({ alignContent: Alignment.Bottom }) {
      Scroll() {
        Column() {
          this.WheelSection()
          this.CustomSection()
        }
        .width('100%')
        .padding(Theme.pageHorizontalPadding)
        .padding({ bottom: this.showResult ? 220 : 24 })
      }
      .width('100%')
      .height('100%')
      .scrollBar(BarState.Off)
      .backgroundColor(Theme.pageBg)

      if (this.showResult) {
        this.ResultSheet()
      }
    }
    .width('100%')
    .height('100%')
  }

  @Builder
  WheelSection() {
    Column() {
      Stack() {
        // Wheel outer ring
        Column() {
          // Wheel canvas represented with conic gradient placeholder
          Stack() {
            Column()
              .width('100%')
              .height('100%')
              .borderRadius(150)
              .backgroundColor(Theme.tomato)

            // Segment separators
            ForEach([0, 60, 120, 180, 240, 300], (angle: number) => {
              Column()
                .width(2)
                .height(150)
                .backgroundColor('#FFFFFF')
                .position({ x: 149, y: 0 })
                .rotate({ angle: angle, centerX: 1, centerY: 150 })
            }, (angle: number) => angle.toString())

            // Wheel labels
            ForEach(this.allItems(), (item: WheelItem, index: number) => {
              Text(item.name)
                .fontSize(13)
                .fontWeight(FontWeight.Bold)
                .fontColor('#FFFFFF')
                .position({
                  x: 150 - 20,
                  y: 40
                })
                .rotate({ angle: index * (360 / Math.max(this.allItems().length, 1)) + 30, centerX: 20, centerY: 110 })
            }, (item: WheelItem) => item.id)

            // Center knob
            Column() {
              SvgIcon({ variant: 'wheelCenter', iconSize: 28, color: Theme.brown })
            }
            .width(72)
            .height(72)
            .borderRadius(36)
            .backgroundColor('#FFFFFF')
            .shadow({ radius: 18, color: 'rgba(62,39,35,0.16)', offsetX: 0, offsetY: 6 })
            .position({ x: 114, y: 114 })
          }
          .width(300)
          .height(300)
          .borderRadius(150)
          .clip(true)
          .rotate({ angle: this.rotation, centerX: 150, centerY: 150 })
          .animation({
            duration: 3000,
            curve: Curve.EaseOut,
            onFinish: () => {
              this.isSpinning = false;
              this.showResult = true;
            }
          })
        }
        .id('wheel-canvas')
        .width(316)
        .height(316)
        .borderRadius(158)
        .backgroundColor('#FFFFFF')
        .padding(8)
        .shadow({ radius: 40, color: 'rgba(62,39,35,0.14)', offsetX: 0, offsetY: 14 })

        // Pointer
        SvgIcon({ variant: 'wheelPointer', iconSize: 28, color: Theme.brown })
          .width(28)
          .height(36)
          .position({ x: 144, y: -10 })
      }
      .width(316)
      .height(340)
      .margin({ top: 24 })

      Button() {
        Row() {
          SvgIcon({ variant: 'spin', iconSize: 20, color: '#FFFFFF' })
          Text('开始转转')
            .fontSize(16)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
            .margin({ left: 8 })
        }
      }
      .id('wheel-spin-button')
      .type(ButtonType.Normal)
      .borderRadius(Theme.radiusButton)
      .linearGradient(BrandGradient.primary)
      .padding({ left: 32, right: 32, top: 16, bottom: 16 })
      .shadow(Theme.shadowFloat())
      .margin({ top: 28 })
      .enabled(!this.isSpinning)
      .onClick(() => this.spinWheel())
    }
    .width('100%')
    .alignItems(HorizontalAlign.Center)
  }

  @Builder
  CustomSection() {
    Text('自定义选项')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 28, bottom: 12 })
      .alignSelf(ItemAlign.Start)

    Row() {
      TextInput({ placeholder: '输入想转的菜品', text: $$this.newItemName })
        .placeholderColor(Theme.brownLight)
        .fontSize(14)
        .height(46)
        .backgroundColor(Theme.cardMutedBg)
        .borderRadius(18)
        .padding({ left: 16, right: 16 })
        .layoutWeight(1)
        .id('wheel-add-item-input')

      Button() {
        SvgIcon({ variant: 'addWheelItem', iconSize: 20, color: '#FFFFFF' })
      }
      .id('wheel-add-item-button')
      .width(46)
      .height(46)
      .type(ButtonType.Normal)
      .borderRadius(16)
      .backgroundColor(Theme.tomato)
      .margin({ left: 10 })
      .onClick(() => this.addCustomItem())
    }
    .width('100%')
    .margin({ bottom: 14 })

    Flex({ wrap: FlexWrap.Wrap }) {
      ForEach(this.customItems, (item: WheelItem) => {
        Row() {
          Text(item.name)
            .fontSize(13)
            .fontColor(Theme.brown)
            .margin({ right: 6 })

          Button() {
            SvgIcon({ variant: 'remove', iconSize: 12, color: Theme.brownLight })
          }
          .id('wheel-remove-item-button')
          .width(18)
          .height(18)
          .type(ButtonType.Normal)
          .borderRadius(9)
          .backgroundColor(Theme.cardMutedBg)
          .onClick(() => this.removeCustomItem(item.id))
        }
        .id(`wheel-item-${item.id}`)
        .padding({ left: 12, right: 8, top: 8, bottom: 8 })
        .backgroundColor(Theme.cardBg)
        .borderRadius(18)
        .shadow(Theme.shadowCard())
        .margin({ right: 8, bottom: 8 })
      }, (item: WheelItem) => item.id)
    }
    .id('wheel-custom-items-list')
    .width('100%')
  }

  @Builder
  ResultSheet() {
    Column() {
      Column()
        .width(40)
        .height(4)
        .borderRadius(2)
        .backgroundColor(Theme.cardMutedBg)
        .margin({ bottom: 18 })

      Column() {
        SvgIcon({ variant: 'wheelResult', iconSize: 48, color: Theme.tomato })
      }
      .width(90)
      .height(90)
      .borderRadius(45)
      .backgroundColor('#FFFFFF')
      .justifyContent(FlexAlign.Center)
      .margin({ bottom: 14 })

      Text(this.resultName)
        .id('wheel-result-name')
        .fontSize(24)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.brown)
        .margin({ bottom: 6 })

      Text('今日好运菜品，去吃它吧！')
        .fontSize(13)
        .fontColor(Theme.brownMid)
        .margin({ bottom: 20 })

      Row() {
        Button('生成卡片')
          .id('wheel-result-share-card')
          .type(ButtonType.Normal)
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.cardMutedBg)
          .fontColor(Theme.brown)
          .fontWeight(FontWeight.Bold)
          .fontSize(14)
          .layoutWeight(1)
          .onClick(() => this.onShareCard())

        Button('加入打卡')
          .id('wheel-result-add-checkin')
          .type(ButtonType.Normal)
          .borderRadius(Theme.radiusButton)
          .linearGradient(BrandGradient.primary)
          .fontColor('#FFFFFF')
          .fontWeight(FontWeight.Bold)
          .fontSize(14)
          .layoutWeight(1)
          .margin({ left: 10 })
          .onClick(() => {
            this.onAddCheckin(this.resultName);
            this.showResult = false;
          })
      }
      .width('100%')
    }
    .width('100%')
    .padding({ left: 20, right: 20, top: 24, bottom: 32 })
    .backgroundColor(Theme.cardBg)
    .borderRadius({ topLeft: 28, topRight: 28 })
    .shadow({ radius: 40, color: 'rgba(62,39,35,0.18)', offsetX: 0, offsetY: -8 })
  }

  private spinWheel(): void {
    if (this.isSpinning) {
      return;
    }
    this.isSpinning = true;
    this.showResult = false;
    const extraRounds: number = 360 * (4 + Math.floor(Math.random() * 3));
    const randomAngle: number = Math.floor(Math.random() * 360);
    this.rotation = this.rotation + extraRounds + randomAngle;

    // Determine result based on final angle
    const total: number = this.allItems().length;
    const segment: number = 360 / total;
    const finalAngle: number = (this.rotation % 360);
    const index: number = Math.floor(((360 - finalAngle + segment / 2) % 360) / segment);
    const selected: WheelItem | undefined = this.allItems()[index];
    if (selected) {
      this.resultName = selected.name;
    }
  }

  private addCustomItem(): void {
    const name: string = this.newItemName.trim();
    if (!name) {
      return;
    }
    this.customItems.push({ id: `c${Date.now()}`, name: name });
    this.newItemName = '';
  }

  private removeCustomItem(id: string): void {
    this.customItems = this.customItems.filter((item: WheelItem) => item.id !== id);
  }
}

