      }
      .id('ingredients-my-list')
      .width('100%')
    }
    .width('100%')
    .padding(18)
    .backgroundColor(Theme.cardBg)
    .borderRadius(Theme.radiusCard)
    .shadow(Theme.shadowCard())
  }

  @Builder
  Recommendations() {
    Text('为你推荐')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 20, bottom: 12 })

    Column({ space: 12 }) {
      ForEach(this.recommendations, (rec: Recommendation) => {
        Row() {
          Column() {
            SvgIcon({ variant: rec.icon, iconSize: 32, color: rec.icon === 'recommend1' ? Theme.tomato : Theme.avocado })
          }
          .width(64)
          .height(64)
          .borderRadius(18)
          .backgroundColor('#FFF9F0')
          .justifyContent(FlexAlign.Center)
          .margin({ right: 14 })

          Column() {
            Text(rec.name)
              .fontSize(15)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brown)
              .margin({ bottom: 4 })

            Row() {
              ForEach(rec.tags, (tag: string) => {
                Text(tag)
                  .fontSize(10)
                  .fontColor(Theme.brownMid)
                  .padding({ left: 8, right: 8, top: 3, bottom: 3 })
                  .backgroundColor(Theme.cardMutedBg)
                  .borderRadius(10)
                  .margin({ right: 6 })
              }, (tag: string) => tag)
            }
            .margin({ bottom: 8 })

            Stack() {
              Row()
                .width('100%')
                .height(6)
                .borderRadius(3)
                .backgroundColor('#F0E6DA')

              Row()
                .id('ingredients-match-score')
                .width(`${rec.score}%`)
                .height(6)
                .borderRadius(3)
                .linearGradient(BrandGradient.matchScore)
                .alignSelf(ItemAlign.Start)
            }
            .width('100%')
            .height(6)
            .margin({ bottom: 4 })

            Text(`匹配度 ${rec.score}%`)
              .fontSize(13)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.avocado)
          }
          .layoutWeight(1)
          .alignItems(HorizontalAlign.Start)

          Button() {
            SvgIcon({ variant: 'arrowRight', iconSize: 20, color: '#FFFFFF' })
          }
          .id('ingredients-cook-now-button')
          .width(40)
          .height(40)
          .type(ButtonType.Normal)
          .borderRadius(14)
          .backgroundColor(Theme.tomato)
          .shadow({ radius: 16, color: 'rgba(232,93,78,0.24)', offsetX: 0, offsetY: 6 })
          .onClick(() => this.onCook(rec.name))
        }
        .id(`ingredient-rec-${rec.id}`)
        .width('100%')
        .padding(16)
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusCard)
        .shadow(Theme.shadowCard())
        .alignItems(VerticalAlign.Center)
      }, (rec: Recommendation) => rec.id)
    }
    .id('ingredients-recommendations-list')
    .width('100%')
  }

  private addIngredient(): void {
    const name: string = this.newIngredient.trim();
    if (!name) {
      return;
    }
    this.myIngredients.push({ id: `${Date.now()}`, name: name });
    this.newIngredient = '';
  }

  private removeIngredient(id: string): void {
    this.myIngredients = this.myIngredients.filter((item: Ingredient) => item.id !== id);
  }
}

