import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

interface Dish {
  id: string;
  name: string;
  tags: string[];
  icon: string;
  iconColor: string;
  bg: string;
}

@Component
export struct DiscoverPage {
  onBack: () => void = () => {};
  onAddDish: () => void = () => {};

  @State searchQuery: string = '';
  @State moods: string[] = ['全部心情', '想吃点暖的', '清爽轻食', '治愈系', '重口味'];
  @State activeMood: string = '全部心情';
  @State times: string[] = ['全部时段', '早餐', '午餐', '晚餐', '夜宵'];
  @State activeTime: string = '全部时段';
  @State durations: string[] = ['不限时长', '15 分钟内', '30 分钟内', '1 小时'];
  @State activeDuration: string = '不限时长';
  @State tastes: string[] = ['全部口味', '酸', '甜', '辣', '咸鲜'];
  @State activeTaste: string = '全部口味';

  @State dishes: Dish[] = [
    { id: '1', name: '番茄鸡蛋打卤面', tags: ['15 分钟', '暖胃'], icon: 'dish1', iconColor: '#E85D4E', bg: 'linear-gradient(135deg, #FFF9F0, #FFE8D6)' },
    { id: '2', name: '清炒西兰花', tags: ['10 分钟', '清淡'], icon: 'dish2', iconColor: '#7FB069', bg: 'linear-gradient(135deg, #EEF7EA, #D8EDD3)' },
    { id: '3', name: '蛋炒饭', tags: ['剩饭改造', '快手'], icon: 'dish3', iconColor: '#F4C542', bg: 'linear-gradient(135deg, #FFF8E1, #FDECB8)' },
    { id: '4', name: '红烧牛肉面', tags: ['治愈', '45 分钟'], icon: 'dish4', iconColor: '#8B7FD4', bg: 'linear-gradient(135deg, #EDEAF9, #DDD8F4)' },
  ];

  build() {
    Stack({ alignContent: Alignment.BottomEnd }) {
      Scroll() {
        Column() {
          this.SearchBox()
          this.FilterSection()
          this.ResultsGrid()
        }
        .width('100%')
        .padding(Theme.pageHorizontalPadding)
        .padding({ bottom: 80 })
        .alignItems(HorizontalAlign.Start)
      }
      .width('100%')
      .height('100%')
      .scrollBar(BarState.Off)
      .backgroundColor(Theme.pageBg)

      Button() {
        SvgIcon({ variant: 'addDish', iconSize: 24, color: '#FFFFFF' })
      }
      .id('discover-add-dish-button')
      .width(52)
      .height(52)
      .type(ButtonType.Normal)
      .borderRadius(26)
      .backgroundColor(Theme.tomato)
      .shadow({ radius: 24, color: 'rgba(232,93,78,0.32)', offsetX: 0, offsetY: 8 })
      .margin({ right: 16, bottom: 88 })
      .onClick(() => this.onAddDish())
    }
    .width('100%')
    .height('100%')
  }

  @Builder
  SearchBox() {
    Stack({ alignContent: Alignment.Start }) {
      TextInput({ placeholder: '搜索菜名、食材或标签', text: $$this.searchQuery })
        .placeholderColor(Theme.brownLight)
        .fontSize(14)
        .height(46)
        .backgroundColor(Theme.cardMutedBg)
        .borderRadius(18)
        .padding({ left: 42, right: 16 })
        .width('100%')
        .id('discover-search-input')

      SvgIcon({ variant: 'search', iconSize: 20, color: Theme.brownLight })
        .margin({ left: 14, top: 13 })
    }
    .width('100%')
    .margin({ top: 12 })
  }

  @Builder
  FilterSection() {
    Column() {
      this.FilterRow(this.moods, this.activeMood, 'discover-mood-filter', (v: string) => this.activeMood = v, Theme.blueberry)
      this.FilterRow(this.times, this.activeTime, 'discover-time-filter', (v: string) => this.activeTime = v, Theme.caramel)
      this.FilterRow(this.durations, this.activeDuration, 'discover-duration-filter', (v: string) => this.activeDuration = v, Theme.egg)
      this.FilterRow(this.tastes, this.activeTaste, 'discover-taste-filter', (v: string) => this.activeTaste = v, Theme.mint)
    }
    .width('100%')
    .margin({ top: 16 })
  }

  @Builder
  FilterRow(items: string[], active: string, id: string, onChange: (value: string) => void, activeColor: string) {
    List({ space: 8 }) {
      ForEach(items, (item: string) => {
        ListItem() {
          Text(item)
            .fontSize(12)
