  @State activeMood: string = '全部心情';
  @State times: string[] = ['全部时段', '早餐', '午餐', '晚餐', '夜宵'];
  @State activeTime: string = '全部时段';
  @State durations: string[] = ['不限时长', '15 分钟内', '30 分钟内', '1 小时'];
  @State activeDuration: string = '不限时长';
  @State tastes: string[] = ['全部口味', '酸', '甜', '辣', '咸鲜'];
  @State activeTaste: string = '全部口味';

  @State dishes: Dish[] = [
    { id: '1', name: '番茄鸡蛋打卤面', tags: ['15 分钟', '暖胃'], icon: 'dish1', iconColor: '#E85D4E', bg: 'linear-gradient(135deg, #FFF9F0, #FFE8D6)' },
    { id: '2', name: '清炒西兰花', tags: ['10 分钟', '清淡'], icon: 'dish2', iconColor: '#7FB069', bg: 'linear-gradient(135deg, #EEF7EA, #D8EDD3)' },
    { id: '3', name: '蛋炒饭', tags: ['剩饭改造', '快手'], icon: 'dish3', iconColor: '#F4C542', bg: 'linear-gradient(135deg, #FFF8E1, #FDECB8)' },
    { id: '4', name: '红烧牛肉面', tags: ['治愈', '45 分钟'], icon: 'dish4', iconColor: '#8B7FD4', bg: 'linear-gradient(135deg, #EDEAF9, #DDD8F4)' },
  ];

  build() {
    Stack({ alignContent: Alignment.BottomEnd }) {
      Scroll() {
        Column() {
          this.SearchBox()
          this.FilterSection()
          this.ResultsGrid()
