    }
    .width('100%')
    .height('100%')
  }

  @Builder
  SearchBox() {
    Stack({ alignContent: Alignment.Start }) {
      TextInput({ placeholder: '搜索菜名、食材或标签', text: $$this.searchQuery })
        .placeholderColor(Theme.brownLight)
        .fontSize(14)
        .height(46)
        .backgroundColor(Theme.cardMutedBg)
        .borderRadius(18)
        .padding({ left: 42, right: 16 })
        .width('100%')
        .id('discover-search-input')

      SvgIcon({ variant: 'search', iconSize: 20, color: Theme.brownLight })
        .margin({ left: 14, top: 13 })
    }
    .width('100%')
    .margin({ top: 12 })
  }

  @Builder
  FilterSection() {
    Column() {
      this.FilterRow(this.moods, this.activeMood, 'discover-mood-filter', (v: string) => this.activeMood = v, Theme.blueberry)
