                .fontColor(Theme.brown)
                .margin({ bottom: 6 })

              Row() {
                ForEach(dish.tags, (tag: string) => {
                  Text(tag)
                    .fontSize(10)
                    .fontColor(Theme.brownMid)
                    .padding({ left: 7, right: 7, top: 3, bottom: 3 })
                    .backgroundColor(Theme.cardMutedBg)
                    .borderRadius(8)
                    .margin({ right: 4 })
                }, (tag: string) => tag)
              }
            }
            .width('100%')
            .padding(12)
            .alignItems(HorizontalAlign.Start)
          }
          .id(`discover-dish-${dish.id}`)
          .width('100%')
          .backgroundColor(Theme.cardBg)
          .borderRadius(Theme.radiusCard)
          .shadow(Theme.shadowCard())
          .clip(true)
        }
      }, (dish: Dish) => dish.id)
    }
    .id('discover-results-list')
