import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

interface CheckIn {
  id: string;
  dish: string;
  date: string;
  mood: string;
  icon: string;
  iconBg: string;
  iconColor: string;
}

@Component
export struct RecordsPage {
  onBack: () => void = () => {};
  onShareCard: () => void = () => {};
  onTodayCheckIn: () => void = () => {};
  onEdit: (id: string) => void = () => {};
  onDelete: (id: string) => void = () => {};

  @State streak: number = 5;
  @State todayIndex: number = 5; // 0=Mon ... 5=Sat
  @State checkins: CheckIn[] = [
    { id: '1', dish: '番茄鸡蛋打卤面', date: '今天 12:30', mood: '满足', icon: 'checkin1', iconBg: '#FFF0ED', iconColor: Theme.tomato },
    { id: '2', dish: '清炒西兰花', date: '昨天 18:45', mood: '健康', icon: 'checkin2', iconBg: '#EEF7EA', iconColor: Theme.avocado },
  ];
  @State weekDays: { label: string; checked: boolean; isToday: boolean; date: string }[] = [
    { label: '一', checked: true, isToday: false, date: '' },
    { label: '二', checked: true, isToday: false, date: '' },
    { label: '三', checked: true, isToday: false, date: '' },
    { label: '四', checked: true, isToday: false, date: '' },
    { label: '五', checked: true, isToday: false, date: '' },
    { label: '六', checked: false, isToday: true, date: '18' },
    { label: '日', checked: false, isToday: false, date: '19' },
  ];

  build() {
    Scroll() {
      Column() {
        this.StreakHero()
        this.CalendarBar()
        this.TodayButton()
        this.CheckInList()
        this.ShareButton()
      }
      .width('100%')
      .padding(Theme.pageHorizontalPadding)
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .scrollBar(BarState.Off)
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  StreakHero() {
    Row() {
      Column() {
        Text('连续打卡')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor('#FFFFFF')
          .opacity(0.9)
          .margin({ bottom: 6 })

        Text(`${this.streak}`)
          .id('records-streak-count')
          .fontSize(48)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
          .lineHeight(48)

        Text('天')
          .fontSize(13)
          .fontColor('#FFFFFF')
          .opacity(0.9)
          .margin({ top: 4 })
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)

      Column() {
        SvgIcon({ variant: 'award', iconSize: 40, color: '#FFFFFF' })
      }
      .width(80)
      .height(80)
      .borderRadius(40)
      .backgroundColor('rgba(255,255,255,0.18)')
      .justifyContent(FlexAlign.Center)
    }
    .width('100%')
    .padding(24)
    .borderRadius(Theme.radiusHero)
    .linearGradient(BrandGradient.primary)
    .shadow({ radius: 32, color: 'rgba(232,93,78,0.28)', offsetX: 0, offsetY: 12 })
    .margin({ top: 12 })
    .justifyContent(FlexAlign.SpaceBetween)
  }

  @Builder
  CalendarBar() {
    Row() {
      ForEach(this.weekDays, (day: { label: string; checked: boolean; isToday: boolean; date: string }, index: number) => {
        Column() {
          Text(day.label)
            .fontSize(11)
            .fontColor(Theme.brownLight)
            .margin({ bottom: 6 })

          if (day.checked) {
            Column() {
              SvgIcon({ variant: 'checked', iconSize: 14, color: '#FFFFFF' })
            }
            .width(32)
            .height(32)
            .borderRadius(16)
            .backgroundColor(Theme.tomato)
            .justifyContent(FlexAlign.Center)
          } else {
            Text(day.date || day.label)
              .fontSize(13)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brown)
              .width(32)
              .height(32)
              .borderRadius(16)
              .borderWidth(day.isToday ? 2 : 0)
              .borderColor(day.isToday ? Theme.tomato : 'transparent')
              .textAlign(TextAlign.Center)
          }
        }
        .layoutWeight(1)
        .alignItems(HorizontalAlign.Center)
      }, (day: { label: string }, index: number) => `${index}-${day.label}`)
    }
    .id('records-calendar')
    .width('100%')
    .padding({ top: 14, bottom: 14, left: 12, right: 12 })
    .backgroundColor(Theme.cardBg)
    .borderRadius(Theme.radiusCard)
    .shadow(Theme.shadowCard())
    .margin({ top: 16 })
  }

  @Builder
  TodayButton() {
    Button() {
      Row() {
        SvgIcon({ variant: 'addDish', iconSize: 20, color: '#FFFFFF' })
        Text('今天吃了什么？')
          .fontSize(15)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
          .margin({ left: 8 })
      }
    }
    .id('records-today-checkin-button')
    .type(ButtonType.Normal)
    .borderRadius(Theme.radiusButton)
    .linearGradient(BrandGradient.primary)
    .padding({ left: 32, right: 32, top: 16, bottom: 16 })
    .shadow(Theme.shadowFloat())
    .width('100%')
    .margin({ top: 20 })
    .onClick(() => this.onTodayCheckIn())
  }

  @Builder
  CheckInList() {
    Text('最近打卡')
      .fontSize(18)
      .fontWeight(FontWeight.Bold)
      .fontColor(Theme.brown)
      .margin({ top: 24, bottom: 12 })

    Column({ space: 12 }) {
      ForEach(this.checkins, (checkin: CheckIn) => {
        Row() {
          Column() {
            SvgIcon({ variant: checkin.icon, iconSize: 24, color: checkin.iconColor })
          }
          .width(48)
          .height(48)
          .borderRadius(16)
          .backgroundColor(checkin.iconBg)
          .justifyContent(FlexAlign.Center)
          .margin({ right: 14 })

          Column() {
            Text(checkin.dish)
              .fontSize(15)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brown)
              .margin({ bottom: 3 })

            Text(`${checkin.date} · ${checkin.mood}`)
              .fontSize(12)
              .fontColor(Theme.brownMid)
          }
          .layoutWeight(1)
          .alignItems(HorizontalAlign.Start)

          Row() {
            Button() {
              SvgIcon({ variant: 'edit', iconSize: 16, color: Theme.brownMid })
            }
            .id('records-edit-checkin-button')
            .width(34)
            .height(34)
            .type(ButtonType.Normal)
            .borderRadius(12)
            .backgroundColor(Theme.cardMutedBg)
            .onClick(() => this.onEdit(checkin.id))

            Button() {
              SvgIcon({ variant: 'trash', iconSize: 16, color: Theme.tomato })
            }
            .id('records-delete-checkin-button')
            .width(34)
            .height(34)
            .type(ButtonType.Normal)
            .borderRadius(12)
            .backgroundColor('#FDEDEC')
            .margin({ left: 8 })
            .onClick(() => this.onDelete(checkin.id))
          }
        }
        .id(`records-checkin-${checkin.id}`)
        .width('100%')
        .padding(16)
        .backgroundColor(Theme.cardBg)
        .borderRadius(Theme.radiusCard)
        .shadow(Theme.shadowCard())
        .alignItems(VerticalAlign.Center)
      }, (checkin: CheckIn) => checkin.id)
    }
    .id('records-checkins-list')
    .width('100%')
  }

  @Builder
  ShareButton() {
    Button() {
      Row() {
        SvgIcon({ variant: 'share', iconSize: 20, color: Theme.brown })
        Text('生成本周分享卡片')
          .fontSize(15)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.brown)
          .margin({ left: 8 })
      }
    }
    .id('records-share-card-button')
    .type(ButtonType.Normal)
    .borderRadius(Theme.radiusButton)
    .backgroundColor(Theme.cardBg)
    .padding({ left: 32, right: 32, top: 16, bottom: 16 })
    .shadow(Theme.shadowCard())
    .width('100%')
    .margin({ top: 24, bottom: 24 })
    .onClick(() => this.onShareCard())
  }
}

