    { id: 1, bg: 'linear-gradient(135deg, #2C2420, #4A3B35)', titleColor: '#FFFFFF', textColor: 'rgba(255,255,255,0.8)', decoColor: 'rgba(255,255,255,0.08)' },
    { id: 2, bg: 'linear-gradient(135deg, #EDEAF9, #DDD8F4)', titleColor: Theme.brown, textColor: Theme.brownMid, decoColor: 'rgba(139,127,212,0.16)' },
