    .scrollBar(BarState.Off)
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  CardPreview() {
    Column() {
      Stack() {
        // Decorative circles
        Column()
          .width(140)
          .height(140)
          .borderRadius(70)
          .backgroundColor(this.templates[this.activeTemplate].decoColor)
          .position({ x: 180, y: -40 })

        Column()
          .width(100)
          .height(100)
          .borderRadius(50)
          .backgroundColor(this.templates[this.activeTemplate].decoColor)
          .position({ x: -30, y: 200 })

        // Content
        Column() {
          Column() {
            Text(this.dateStr)
              .fontSize(12)
              .fontColor(this.templates[this.activeTemplate].textColor)
