9	@Component
10	export struct WheelPage {
11	  onBack: () => void = () => {};
12	  onShareCard: () => void = () => {};
13	  onAddCheckin: (dish: string) => void = () => {};
14	
15	  @State wheelItems: WheelItem[] = [
16	    { id: '1', name: '牛肉面' },
17	    { id: '2', name: '番茄炒蛋' },
18	    { id: '3', name: '沙拉' },
19	    { id: '4', name: '炒饭' },
20	    { id: '5', name: '煎饼果子' },
21	    { id: '6', name: '麻辣烫' },
22	  ];
23	  @State customItems: WheelItem[] = [
24	    { id: 'c1', name: '火锅' },
25	    { id: 'c2', name: '日料' },
26	    { id: 'c3', name: '披萨' },
27	  ];
28	  @State newItemName: string = '';
29	  @State resultName: string = '番茄鸡蛋打卤面';
30	  @State showResult: boolean = true;
31	  @State rotation: number = 0;
32	  @State isSpinning: boolean = false;
33	
34	  private allItems(): WheelItem[] {
35	    return [...this.wheelItems, ...this.customItems];
36	  }
37	
38	  build() {
39	    Stack({ alignContent: Alignment.Bottom }) {
40	      Scroll() {
41	        Column() {
42	          this.WheelSection()
43	          this.CustomSection()
44	        }
45	        .width('100%')
46	        .padding(Theme.pageHorizontalPadding)
47	        .padding({ bottom: this.showResult ? 220 : 24 })
48	      }
49	      .width('100%')
50	      .height('100%')
51	      .scrollBar(BarState.Off)
52	      .backgroundColor(Theme.pageBg)
53	
54	      if (this.showResult) {
55	        this.ResultSheet()
56	      }
57	    }
58	    .width('100%')
59	    .height('100%')
60	  }
61	
62	  @Builder
63	  WheelSection() {
64	    Column() {
65	      Stack() {
66	        // Wheel outer ring
67	        Column() {
68	          // Wheel canvas represented with conic gradient placeholder
69	          Stack() {
70	            Column()
71	              .width('100%')
72	              .height('100%')
73	              .borderRadius(150)
74	              .backgroundColor(Theme.tomato)
75	
76	            // Segment separators
77	            ForEach([0, 60, 120, 180, 240, 300], (angle: number) => {
78	              Column()
79	                .width(2)
80	                .height(150)
81	                .backgroundColor('#FFFFFF')
82	                .position({ x: 149, y: 0 })
83	                .rotate({ angle: angle, centerX: 1, centerY: 150 })
84	            }, (angle: number) => angle.toString())
85	
