import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

interface Ingredient {
  id: string;
  name: string;
}

interface Recommendation {
  id: string;
  name: string;
  tags: string[];
  score: number;
  icon: string;
}

@Component
export struct IngredientsPage {
  onBack: () => void = () => {};
  onCook: (dish: string) => void = () => {};

  @State categories: string[] = ['全部', '蔬菜', '肉蛋', '水产', '豆制品', '主食', '调料'];
  @State activeCategory: string = '全部';
  @State searchQuery: string = '';
  @State newIngredient: string = '';
  @State myIngredients: Ingredient[] = [
    { id: '1', name: '番茄' },
    { id: '2', name: '鸡蛋' },
    { id: '3', name: '青菜' },
    { id: '4', name: '面条' },
  ];
  @State recommendations: Recommendation[] = [
    { id: '1', name: '番茄鸡蛋打卤面', tags: ['15 分钟', '家常'], score: 92, icon: 'recommend1' },
    { id: '2', name: '青菜鸡蛋汤面', tags: ['10 分钟', '清淡'], score: 78, icon: 'recommend2' },
  ];

  build() {
    Scroll() {
      Column() {
        this.SearchAndAdd()
        this.CategoryTabs()
        this.MyFridge()
        this.Recommendations()
      }
      .width('100%')
      .padding(Theme.pageHorizontalPadding)
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
    .scrollBar(BarState.Off)
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  SearchAndAdd() {
    Column() {
      Stack({ alignContent: Alignment.Start }) {
        TextInput({ placeholder: '搜索食材，如番茄、牛肉', text: $$this.searchQuery })
          .placeholderColor(Theme.brownLight)
          .fontSize(14)
          .height(46)
          .backgroundColor(Theme.cardMutedBg)
          .borderRadius(18)
          .padding({ left: 42, right: 16 })
          .width('100%')
          .id('ingredients-search-input')

        SvgIcon({ variant: 'search', iconSize: 20, color: Theme.brownLight })
          .margin({ left: 14, top: 13 })
      }
      .width('100%')
      .margin({ bottom: 12 })

      Row() {
        TextInput({ placeholder: '添加新食材', text: $$this.newIngredient })
          .placeholderColor(Theme.brownLight)
          .fontSize(14)
          .height(46)
          .backgroundColor(Theme.cardMutedBg)

