import json
with open('full_dump_eatwhat_20260619101943596.json') as f:
    data = json.load(f)

def find_nodes(node, cond, depth=0):
    results = []
    try:
        if cond(node):
            results.append((depth, node))
    except Exception:
        pass
    for child in node.get('$children', []):
        results.extend(find_nodes(child, cond, depth+1))
    return results

ids = ['home-today-recommendation-card', 'home-spin-wheel-button', 'home-ingredients-button', 
       'home-discover-button', 'home-records-button', 'bottom-tab-bar', 'tab-home', 'tab-wheel']
for target in ids:
    nodes = find_nodes(data, lambda n: n.get('$attrs', {}).get('id') == target)
    print(f'{target}: {len(nodes)} found')

# Check all ids present
all_ids = []
def collect_ids(node):
    try:
        id_val = node.get('$attrs', {}).get('id')
        if id_val:
            all_ids.append(id_val)
    except Exception:
        pass
    for child in node.get('$children', []):
        collect_ids(child)
collect_ids(data)
print()
print('All ids count:', len(all_ids))
print('First 20 ids:', all_ids[:20])
"

