        for k, v in node.items():
            if depth < max_depth and isinstance(v, (dict, list)):
                print('  '*(depth+1) + k + ':')
                if isinstance(v, list):
                    for i, item in enumerate(v[:2]):
                        show_keys(item, depth+2, max_depth)
                else:
                    show_keys(v, depth+2, max_depth)

show_keys(data, 0, 2)
